import React, { useState, useEffect, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, ConfirmDialog, Pagination, SectionTitle } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, CheckSquare, Square, MinusSquare, Shield, ChevronDown, Folder, UserPlus, Lock, ChevronRight } from 'lucide-react';
import { MOCK_ROLES, REGIONS, MOCK_DOMAINS, MOCK_MENUS, BUSINESS_TYPES } from '../constants';
import { Role, Domain, Menu } from '../types';
import { useGlobalContext } from '../GlobalContext';

// Type to represent either a domain header or a role item row
type TreeItem = 
  | { type: 'domain'; id: string; data: Domain; roleCount: number; expanded: boolean }
  | { type: 'role'; id: string; data: Role; parentDomainId: string };

const ITEMS_PER_PAGE = 8;

export const RoleManager: React.FC = () => {
  const { mode, currentDomain } = useGlobalContext();
  const [roleData, setRoleData] = useState<Role[]>(MOCK_ROLES);
  const [currentPage, setCurrentPage] = useState(1);

  // Expanded Domains State
  const [expandedDomains, setExpandedDomains] = useState<Set<string>>(new Set(MOCK_DOMAINS.map(d => d.id)));

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentRole, setCurrentRole] = useState<Partial<Role>>({});

  // Menu Permissions State (IDs)
  const [selectedMenuIds, setSelectedMenuIds] = useState<Set<string>>(new Set());

  const [isDomainLocked, setIsDomainLocked] = useState(false); // New state to control select lock
  const [activeTab, setActiveTab] = useState<'info' | 'menu' | 'data'>('info');

  // Search
  const [searchName, setSearchName] = useState('');
  const [searchCode, setSearchCode] = useState('');
  const [searchDomainId, setSearchDomainId] = useState('');

  // Delete Confirmation
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);

  // --- Mock Transfer Data State ---
  const [sourceData] = useState(() => {
      const list = [];
      for(let i=1; i<=8; i++) list.push({ id: `line-${i}`, name: `互联网专线-电路${i}`, category: 'BIZ_LINE' });
      for(let i=1; i<=8; i++) list.push({ id: `5g-${i}`, name: `5G切片-车间${i}`, category: 'BIZ_5G' });
      for(let i=1; i<=8; i++) list.push({ id: `idc-${i}`, name: `IDC机柜-机房${i}`, category: 'BIZ_IDC' });
      for(let i=1; i<=5; i++) list.push({ id: `comp-${i}`, name: `东数西算-节点${i}`, category: 'BIZ_COMP' });
      return list;
  });
  const [targetKeys, setTargetKeys] = useState<string[]>([]); 
  const [sourceSelected, setSourceSelected] = useState<string[]>([]);
  const [targetSelected, setTargetSelected] = useState<string[]>([]);
  const [bizCategoryFilter, setBizCategoryFilter] = useState<string>('all');

  // Handle Context Change
  useEffect(() => {
    setCurrentPage(1);
    setSearchName('');
    setSearchCode('');
    setSearchDomainId('');
    if (mode === 'switching' && currentDomain) {
        setExpandedDomains(new Set([currentDomain.id]));
    } else {
        setExpandedDomains(new Set(MOCK_DOMAINS.map(d => d.id)));
    }
  }, [mode, currentDomain]);

  useEffect(() => {
    if (isModalOpen) {
        setTargetKeys([]); 
        setSourceSelected([]);
        setTargetSelected([]);
        setBizCategoryFilter('all');
    }
  }, [isModalOpen]);

  const toggleDomain = (domainId: string) => {
      const newSet = new Set(expandedDomains);
      if (newSet.has(domainId)) {
          newSet.delete(domainId);
      } else {
          newSet.add(domainId);
      }
      setExpandedDomains(newSet);
  };

  // --- Process Data into Flat Tree Structure ---
  const flatTreeData = useMemo(() => {
    // 1. Determine Context
    let contextDomains = MOCK_DOMAINS;
    if (mode === 'switching' && currentDomain) {
        contextDomains = MOCK_DOMAINS.filter(d => d.id === currentDomain.id);
    }

    let filteredRoles = roleData;
    if (searchName) filteredRoles = filteredRoles.filter(r => r.name.includes(searchName));
    if (searchCode) filteredRoles = filteredRoles.filter(r => r.code.includes(searchCode));

    // Strictly filter roles in switching mode
    if (mode === 'switching' && currentDomain) {
        filteredRoles = filteredRoles.filter(r => r.domainId === currentDomain.id);
    }

    const result: TreeItem[] = [];
    contextDomains.forEach(domain => {
        // Filter by Domain ID if selected in local search
        if (searchDomainId && domain.id !== searchDomainId) return;

        const domainRoles = filteredRoles.filter(r => r.domainId === domain.id);

        // If searching by name/code and no roles match, skip this domain
        if ((searchName || searchCode) && domainRoles.length === 0) return; 

        // Auto expand if searching or filtering or switching
        const isExpanded = expandedDomains.has(domain.id) || !!searchName || !!searchCode || !!searchDomainId || (mode === 'switching');

        result.push({
            type: 'domain',
            id: `d-${domain.id}`,
            data: domain,
            roleCount: domainRoles.length,
            expanded: isExpanded
        });

        if (isExpanded) {
            domainRoles.forEach(role => {
                result.push({
                    type: 'role',
                    id: role.id,
                    data: role,
                    parentDomainId: domain.id
                });
            });
        }
    });

    return result;
  }, [roleData, expandedDomains, searchName, searchCode, searchDomainId, mode, currentDomain]);

  // Pagination
  const totalPages = Math.ceil(flatTreeData.length / ITEMS_PER_PAGE);
  const paginatedData = flatTreeData.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  // --- Handlers ---
  const moveToRight = () => {
    setTargetKeys([...targetKeys, ...sourceSelected]);
    setSourceSelected([]);
  };
  const moveToLeft = () => {
    setTargetKeys(targetKeys.filter(k => !targetSelected.includes(k)));
    setTargetSelected([]);
  };

  const handleEdit = (role: Role) => {
    setCurrentRole({ ...role });
    setIsDomainLocked(true); 
    setSelectedMenuIds(new Set(role.menuIds || []));
    setActiveTab('info');
    setIsModalOpen(true);
  };

  // Triggered by Top Button
  const handleGlobalAdd = () => {
    // If in switching mode, force current domain
    const defaultDomainId = (mode === 'switching' && currentDomain) ? currentDomain.id : (MOCK_DOMAINS[0]?.id || '');

    setCurrentRole({ 
        domainId: defaultDomainId, 
        regionScope: [], 
        bizCategoryScope: [] 
    });
    setSelectedMenuIds(new Set(['1', '11'])); 
    // Lock domain if in switching mode
    setIsDomainLocked(mode === 'switching');
    setActiveTab('info');
    setIsModalOpen(true);
  };

  // Triggered by Domain Row Button
  const handleAddInDomain = (domainId: string) => {
    setCurrentRole({ 
        domainId: domainId, 
        regionScope: [], 
        bizCategoryScope: [] 
    });
    setSelectedMenuIds(new Set(['1', '11']));
    setIsDomainLocked(true);
    setActiveTab('info');
    setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
      setDeleteId(id);
      setConfirmOpen(true);
  };

  const confirmDelete = () => {
      if (deleteId) {
          setRoleData(roleData.filter(r => r.id !== deleteId));
      }
      setConfirmOpen(false);
      setDeleteId(null);
  };

  const handleSave = () => {
      const roleToSave = {
          ...currentRole,
          menuIds: Array.from(selectedMenuIds)
      } as Role;

      if (roleToSave.id) {
          setRoleData(roleData.map(r => r.id === roleToSave.id ? roleToSave : r));
      } else {
          const newRole = { 
              ...roleToSave, 
              id: Date.now().toString(),
              code: roleToSave.code || `ROLE_${Date.now()}` 
          } as Role;
          setRoleData([...roleData, newRole]);
      }
      setIsModalOpen(false);
  };

  // --- Menu Logic ---
  const getChildIds = (menu: Menu): string[] => {
      let ids: string[] = [];
      if (menu.children) {
          menu.children.forEach(child => {
              ids.push(child.id);
              ids = [...ids, ...getChildIds(child)];
          });
      }
      return ids;
  };

  const getParentIds = (targetId: string, menus: Menu[], path: string[] = []): string[] => {
      for (const menu of menus) {
          if (menu.id === targetId) return path;
          if (menu.children) {
              const res = getParentIds(targetId, menu.children, [...path, menu.id]);
              if (res.length > 0) return res;
          }
      }
      return [];
  };

  const toggleMenu = (menu: Menu, checked: boolean) => {
      const newSelected = new Set(selectedMenuIds);
      const childIds = getChildIds(menu);
      if (checked) {
          newSelected.add(menu.id);
          childIds.forEach(id => newSelected.add(id));
          const parentIds = getParentIds(menu.id, MOCK_MENUS);
          parentIds.forEach(id => newSelected.add(id));
      } else {
          newSelected.delete(menu.id);
          childIds.forEach(id => newSelected.delete(id));
          // Note: We deliberately do NOT remove parent IDs when a child is unchecked
          // to maintain folder access even if only partial children are selected.
      }
      setSelectedMenuIds(newSelected);
  };

  type CheckState = 'checked' | 'unchecked' | 'indeterminate';

  const getMenuState = (menu: Menu): CheckState => {
      // If it's a leaf node or has no children loaded
      if (!menu.children || menu.children.length === 0) {
          return selectedMenuIds.has(menu.id) ? 'checked' : 'unchecked';
      }

      // If it has children, we need to check their status
      let allChecked = true;
      let allUnchecked = true;

      const checkChildren = (children: Menu[]) => {
        for (const child of children) {
            const childIsSelected = selectedMenuIds.has(child.id);
            if (!childIsSelected) allChecked = false;
            else allUnchecked = false;

            // Recurse
            if (child.children) {
                checkChildren(child.children);
            }
        }
      };

      checkChildren(menu.children);

      if (allChecked) return 'checked';
      if (allUnchecked) return selectedMenuIds.has(menu.id) ? 'checked' : 'unchecked'; // If explicitly selected but children empty (rare case)
      return 'indeterminate';
  };

  const renderMenuTree = (menus: Menu[], depth = 0) => {
      return menus.map(menu => {
          const state = getMenuState(menu);

          return (
              <div key={menu.id}>
                  <div 
                      className={`flex items-center space-x-2 py-1.5 cursor-pointer hover:bg-slate-800 rounded px-2 transition-colors`}
                      style={{ paddingLeft: `${depth * 20 + 8}px` }}
                      onClick={() => toggleMenu(menu, state !== 'checked')}
                  >
                      {state === 'checked' && <CheckSquare size={16} className="text-blue-500 shrink-0" />}
                      {state === 'indeterminate' && <MinusSquare size={16} className="text-blue-500 shrink-0" />}
                      {state === 'unchecked' && <Square size={16} className="text-slate-500 shrink-0" />}

                      <span className={`${state !== 'unchecked' ? 'text-white' : 'text-slate-400'} text-sm select-none`}>{menu.name}</span>
                  </div>
                  {menu.children && renderMenuTree(menu.children, depth + 1)}
              </div>
          );
      });
  };

  const isAllRegionsSelected = (currentRole.regionScope?.length || 0) === REGIONS.length;
  const toggleAllRegions = () => {
      if (isAllRegionsSelected) {
          setCurrentRole({ ...currentRole, regionScope: [] });
      } else {
          setCurrentRole({ ...currentRole, regionScope: REGIONS.map(r => r.code) });
      }
  };
  const toggleRegion = (code: string) => {
      const current = currentRole.regionScope || [];
      if (current.includes(code)) {
          setCurrentRole({ ...currentRole, regionScope: current.filter(c => c !== code) });
      } else {
          setCurrentRole({ ...currentRole, regionScope: [...current, code] });
      }
  };

  const filteredSourceData = useMemo(() => {
      let res = sourceData.filter(d => !targetKeys.includes(d.id));
      if (bizCategoryFilter !== 'all') {
          res = res.filter(d => d.category === bizCategoryFilter);
      }
      return res;
  }, [sourceData, targetKeys, bizCategoryFilter]);


  // --- Render Table Columns ---
  const columns = [
    { 
      header: '名称 / 组织', 
      accessor: (row: TreeItem) => {
          if (row.type === 'domain') {
              return (
                  <div 
                    className="flex items-center cursor-pointer select-none text-slate-200 hover:text-white group"
                    onClick={() => toggleDomain(row.data.id)}
                  >
                      <div className="mr-2 text-slate-500 transition-transform duration-200">
                          {row.expanded ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
                      </div>
                      <Folder size={18} className="mr-2 text-blue-500 fill-blue-500/10 group-hover:text-blue-400" />
                      <span className="font-bold text-base mr-2">{row.data.name}</span>
                      <Badge color="gray" className="scale-90">{row.roleCount} 角色</Badge>
                  </div>
              );
          } else {
              return (
                  <div className="flex items-center pl-10 text-slate-300 relative">
                      <div className="absolute left-[29px] top-[-20px] bottom-[50%] w-[1px] bg-slate-700"></div>
                      <div className="absolute left-[29px] top-[50%] w-4 h-[1px] bg-slate-700"></div>
                      <Shield size={16} className="mr-2 text-green-500" />
                      <span className="font-medium hover:text-green-400 transition-colors cursor-default">{row.data.name}</span>
                  </div>
              );
          }
      },
      width: '35%'
    },
    { 
      header: '编码', 
      accessor: (row: TreeItem) => row.type === 'role' ? <Badge color="gray">{row.data.code}</Badge> : <span className="text-slate-600 text-xs italic opacity-50">{row.data.code}</span>,
      width: '20%'
    },
    { 
      header: '描述', 
      accessor: (row: TreeItem) => row.type === 'role' ? <span className="text-slate-400 text-sm truncate block max-w-xs">{row.data.description}</span> : '',
    },
    {
      header: '操作',
      accessor: (row: TreeItem) => {
          if (row.type === 'domain') {
              return (
                <Button size="sm" variant="ghost" className="text-blue-500 hover:bg-blue-500/10 hover:text-blue-400" icon={<Plus size={14} />} onClick={() => handleAddInDomain(row.data.id)}>
                    新增角色
                </Button>
              )
          }
          return (
            <div className="flex space-x-2">
              <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row.data)}>配置</Button>
              <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.data.id)}>删除</Button>
            </div>
          )
      },
      width: '200px'
    }
  ];

  return (
    <div className="h-full flex flex-col space-y-4">
      {/* Search Bar */}
      <Card className="shrink-0">
         <div className="flex justify-between items-center">
            <div className="flex gap-4">
                <Input placeholder="搜索角色名称" className="w-48" value={searchName} onChange={e => { setSearchName(e.target.value); setCurrentPage(1); }} />
                <Input placeholder="搜索角色编码" className="w-48" value={searchCode} onChange={e => { setSearchCode(e.target.value); setCurrentPage(1); }} />
                {/* Hide Domain Select in Switching Mode as it is implicit */}
                {mode === 'fusion' && (
                    <Select 
                        className="w-40" 
                        options={[{label: '全部域', value: ''}, ...MOCK_DOMAINS.map(d => ({label: d.name, value: d.id}))]}
                        value={searchDomainId}
                        onChange={e => { setSearchDomainId(e.target.value); setCurrentPage(1); }}
                    />
                )}
                <div className="flex gap-2 pb-0.5">
                    <Button icon={<Search size={16} />}>查询</Button>
                    <Button variant="secondary" icon={<RotateCcw size={16} />} onClick={() => { setSearchName(''); setSearchCode(''); setSearchDomainId(''); setCurrentPage(1); }}>重置</Button>
                </div>
            </div>
            <Button variant="primary" className="bg-green-600 hover:bg-green-500" icon={<UserPlus size={16} />} onClick={handleGlobalAdd}>新增角色</Button>
         </div>
      </Card>

      {/* Role Tree Table */}
      <Card className="flex-1 overflow-hidden flex flex-col" title={mode === 'switching' && currentDomain ? `[${currentDomain.name}] 角色权限树` : "角色权限树"}>
        <div className="flex-1 overflow-auto">
          <Table columns={columns} data={paginatedData} keyField="id" />
        </div>
        <div className="py-2 border-t border-slate-700 flex justify-between items-center">
            <div className="text-sm text-slate-400">共 {flatTreeData.length} 条记录</div>
            <Pagination currentPage={currentPage} totalPages={totalPages} onPageChange={setCurrentPage} />
        </div>
      </Card>

      {/* Add/Edit Modal */}
      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={currentRole.id ? "配置角色权限" : "新增角色"}
        size="lg"
        footer={
            <>
              <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
              <Button onClick={handleSave}>保存配置</Button>
            </>
          }
      >
         <div className="h-[550px] flex flex-col">
            {/* Tabs */}
            <div className="flex border-b border-slate-700 mb-4 shrink-0 bg-[#0f172a] -mx-8 px-8 sticky top-0 z-10">
                {(['info', 'menu', 'data'] as const).map(tab => (
                    <button 
                        key={tab}
                        onClick={() => setActiveTab(tab)}
                        className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === tab ? 'border-blue-500 text-blue-400' : 'border-transparent text-slate-400 hover:text-slate-200'}`}
                    >
                        {tab === 'info' && '基本信息'}
                        {tab === 'menu' && '菜单权限'}
                        {tab === 'data' && '数据权限'}
                    </button>
                ))}
            </div>

            {/* Tab Content Area */}
            <div className="flex-1 overflow-y-auto custom-scrollbar p-1">
                {/* 1. Basic Info */}
                {activeTab === 'info' && (
                    <div className="space-y-6 max-w-2xl mx-auto mt-4">
                         <SectionTitle title="角色基础信息" />
                         <div className="grid grid-cols-2 gap-x-8 gap-y-6">
                            <Input 
                                label="角色名称" 
                                value={currentRole.name || ''} 
                                onChange={e => setCurrentRole({...currentRole, name: e.target.value})}
                                placeholder="请输入角色名称" 
                            />
                            <Input 
                                label="角色编码" 
                                value={currentRole.code || ''} 
                                onChange={e => setCurrentRole({...currentRole, code: e.target.value})}
                                placeholder="ROLE_..." 
                                disabled={!!currentRole.id}
                            />
                            <div className="relative">
                                <Select 
                                    label="所属域" 
                                    options={MOCK_DOMAINS.map(d => ({ label: d.name, value: d.id }))}
                                    value={currentRole.domainId}
                                    onChange={e => setCurrentRole({...currentRole, domainId: e.target.value})}
                                    disabled={isDomainLocked} 
                                    className={isDomainLocked ? "opacity-60 cursor-not-allowed bg-slate-800" : ""}
                                />
                                {isDomainLocked && (
                                    <div className="absolute right-8 top-9 text-slate-500 pointer-events-none flex items-center gap-1">
                                        <Lock size={12} />
                                        <span className="text-xs">已锁定</span>
                                    </div>
                                )}
                            </div>
                            <Input 
                                label="描述" 
                                value={currentRole.description || ''}
                                onChange={e => setCurrentRole({...currentRole, description: e.target.value})}
                            />
                        </div>
                    </div>
                )}
                {/* 2. Menu Permissions */}
                {activeTab === 'menu' && (
                    <div className="space-y-4">
                        <div className="bg-blue-900/10 border border-blue-900/30 rounded p-3 text-xs text-blue-300 mb-2 flex items-center gap-2">
                             <CheckSquare size={14} />
                            提示：勾选该角色可访问的菜单资源。系统支持父子菜单联动选择。
                        </div>
                        <div className="border border-slate-700 rounded-lg p-5 bg-[#1e293b]/30 min-h-[350px]">
                            {renderMenuTree(MOCK_MENUS)}
                        </div>
                    </div>
                )}
                {/* 3. Data Permissions */}
                {activeTab === 'data' && (
                    <div className="space-y-6">
                        {/* Region Scope */}
                        <div className="bg-slate-800/30 p-5 rounded-lg border border-slate-700">
                            <div className="flex justify-between items-center mb-4">
                                <SectionTitle title="区域范围 (Region Scope)" className="mb-0" />
                                <label className="flex items-center space-x-2 cursor-pointer text-xs text-blue-400 hover:text-blue-300 select-none bg-blue-900/20 px-2 py-1 rounded">
                                    <input 
                                        type="checkbox" 
                                        className="rounded bg-slate-900 border-slate-600 text-blue-500"
                                        checked={isAllRegionsSelected}
                                        onChange={toggleAllRegions}
                                    />
                                    <span>全选所有区域</span>
                                </label>
                            </div>
                            <div className="grid grid-cols-4 gap-4">
                                {REGIONS.slice(0, 16).map(reg => (
                                    <label key={reg.code} className="flex items-center space-x-2 cursor-pointer hover:text-blue-400 group">
                                        <input 
                                            type="checkbox" 
                                            className="rounded bg-slate-900 border-slate-600 text-blue-500 focus:ring-offset-slate-900" 
                                            checked={currentRole.regionScope?.includes(reg.code) || false}
                                            onChange={() => toggleRegion(reg.code)}
                                        />
                                        <span className="text-sm text-slate-400 group-hover:text-slate-200">{reg.name}</span>
                                    </label>
                                ))}
                            </div>
                        </div>
                         {/* Business Scope (Transfer) */}
                         <div className="bg-slate-800/30 p-5 rounded-lg border border-slate-700">
                            <SectionTitle title="业务范围 (Business Scope)" />

                            <div className="flex h-[320px] gap-4">
                                {/* Source Panel */}
                                <div className="flex-1 border border-slate-700 rounded-lg flex flex-col bg-[#0f172a]">
                                    <div className="p-2 border-b border-slate-700 bg-slate-800/50 rounded-t-lg flex flex-col gap-2">
                                        <div className="flex justify-between items-center px-1 pt-1">
                                            <span className="text-xs font-semibold text-slate-300">待选业务</span>
                                            <span className="text-xs text-slate-500">{sourceSelected.length} 选中</span>
                                        </div>

                                        {/* Business Category Filter */}
                                        <div className="flex gap-1 overflow-x-auto pb-1 no-scrollbar">
                                            <button 
                                                onClick={() => setBizCategoryFilter('all')}
                                                className={`px-2 py-1 text-[10px] rounded whitespace-nowrap transition-colors border ${bizCategoryFilter === 'all' ? 'bg-blue-600 border-blue-600 text-white' : 'bg-slate-800 border-slate-600 text-slate-400 hover:border-slate-500'}`}
                                            >
                                                全部
                                            </button>
                                            {BUSINESS_TYPES.map(bt => (
                                                <button 
                                                    key={bt.code}
                                                    onClick={() => setBizCategoryFilter(bt.code)}
                                                    className={`px-2 py-1 text-[10px] rounded whitespace-nowrap transition-colors border ${bizCategoryFilter === bt.code ? 'bg-blue-600 border-blue-600 text-white' : 'bg-slate-800 border-slate-600 text-slate-400 hover:border-slate-500'}`}
                                                >
                                                    {bt.name}
                                                </button>
                                            ))}
                                        </div>

                                        <Input placeholder="搜索业务实例..." className="text-xs py-1.5 h-8" />
                                    </div>
                                    <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
                                        {filteredSourceData.map(item => (
                                            <div 
                                                key={item.id} 
                                                className={`flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer ${sourceSelected.includes(item.id) ? 'bg-blue-600/20' : ''}`}
                                                onClick={() => {
                                                    sourceSelected.includes(item.id) 
