                    <div className="w-px h-4 bg-slate-600 mx-1"></div>
                    <button className="text-slate-400 hover:text-white" onClick={() => setTransform({ x: 100, y: 100, scale: 0.6 })}>重置</button>
                </div>

                {/* Canvas Wrapper */}
                <div 
