import React, { useState, useMemo } from 'react';
import { Card, Button, Badge, Input, SectionTitle } from '../components/UI';
import { Search, Plus, MoreVertical, Edit2, Play, Monitor } from 'lucide-react';
import { MOCK_TEMPLATES, BUSINESS_TYPES } from '../constants';
import { useGlobalContext } from '../GlobalContext';
import { TemplateEditor } from '../components/TemplateEditor';

export const TemplateManager: React.FC = () => {
  const { mode, currentDomain } = useGlobalContext();
  const [search, setSearch] = useState('');
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [editingTemplate, setEditingTemplate] = useState<any>(null);

  // Filter templates based on domain (Switching mode only shows domain specific templates based on Customer ID)
  const filteredTemplates = useMemo(() => {
    let list = MOCK_TEMPLATES;

    // In Switching Mode, we filter by the customers that belong to the current domain
    if (mode === 'switching' && currentDomain) {
        const allowedCustomerIds = currentDomain.customerIds || [];
        list = list.filter(t => t.customerId && allowedCustomerIds.includes(t.customerId));
    }

    if (search) {
