                                    <label className="text-xs text-slate-400 block mb-1.5">背景颜色</label>
                                    <div className="flex gap-2">
                                        <Input 
                                            value={pageConfig.bgColor}
                                            onChange={e => setPageConfig({...pageConfig, bgColor: e.target.value})}
